mapper.update:
UPDATE alarm
status = #{status}, handle_method = #{handleMethod}, handle_remark = #{handleRemark}, handler_id = #{handlerId}, handler_name = #{handlerName}, handle_time = #{handleTime}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT id, alarm_no, vehicle_id, vehicle_plate, task_id,
       alarm_type, alarm_level, alarm_content,
       longitude, latitude, status,
       handle_method, handle_remark, handler_id, handler_name,
       alarm_time, handle_time, create_time, update_time
FROM alarm

    
        AND status = #{status}
    
    
        AND alarm_type = #{alarmType}
    
    
        AND alarm_level = #{alarmLevel}
    
    
        AND vehicle_id = #{vehicleId}
    
    
        AND alarm_time >= #{startTime}
    
    
        AND alarm_time <= #{endTime}
    

ORDER BY alarm_time DESC
LIMIT #{limit} OFFSET #{offset}
